import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(from_pos, to_pos, speed):
        return np.linalg.norm(to_pos - from_pos) / speed

    def urgency_weight(window_start, window_end, current_time):
        # Prioritize customers whose time windows are closing soon
        if current_time > window_start:
            return (current_time - window_start) / (window_end - window_start + 1)
        return 0

    best_node = None
    min_cost = float('inf')

    for idx, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos, truck_speed)
        arrival_time = current_time + travel_time
        window_start, window_end = time_windows[idx]

        if arrival_time > window_end:
            continue # Skip if the truck would arrive after the window closes

        if arrival_time < window_start:
            waiting_time = window_start - arrival_time
        else:
            waiting_time = 0

        urgency = urgency_weight(window_start, window_end, current_time)
        cost = travel_time + (waiting_time / 2) - urgency  # Encourage waiting if early but consider urgency

        if cost < min_cost:
            min_cost = cost
            best_node = idx

    return best_node

