        return np.linalg.norm(point1 - point2)

    def urgency_factor(time_window, remaining_customers):
        more_customers_bonus = 10 if remaining_customers > 3 else 5
        start, end = time_window
        close_to_end = max(0, (end - current_time))
        return 1 / (1 + close_to_end) + more_customers_bonus

    def environmental_impact(distance):
        return np.exp(-distance/10)  # Promote shorter, more energy-efficient routes

    best_node = None
    lowest_score = float('inf')
    remaining_customers = len(unvisited_customers)

    for index, customer_pos in enumerate(unvisited_customers):
        distance_to_customer = calculate_distance(cur_truck_pos, customer_pos)
        travel_time_to_customer = distance_to_customer / truck_speed
        expected_arrival = current_time + travel_time_to_customer

        urgency = urgency_factor(time_windows[index], remaining_customers)

        if expected_arrival < time_windows[index][0]:
            penalty = (time_windows[index][0] - expected_arrival) * 2  # waiting penalty
        elif expected_arrival > time_windows[index][1]:
            penalty = (expected_arrival - time_windows[index][1]) * 15  # late penalty
        else:
            penalty = 0

        environmental_score = environmental_impact(distance_to_customer)

        total_score = 3 * travel_time_to_customer + 5 * penalty - 7 * urgency + 2 * environmental_score

        if total_score < lowest_score:
